      <input name="email" type="email" required />
      <button type="submit" disabled={createUser.isPending}>
        {createUser.isPending ? 'Creating...' : 'Create'}
      </button>
      {createUser.isError && <p>Error: {createUser.error.message}</p>}
    </form>
  );
}
